        }

        .cred-field { display: flex; flex-direction: column; gap: 4px; }

        .cred-label {
          font-size: 0.6rem;
          letter-spacing: 0.14em;
          text-transform: uppercase;
          color: var(--text-muted);
          font-weight: 700;
        }

        .cred-input {
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-radius: 6px;
          color: var(--text);
          font-family: var(--font-mono);
          font-size: 0.75rem;
          padding: 8px 10px;
          transition: border-color 0.2s;
        }

        .cred-input:focus {
          outline: none;
          border-color: rgba(255,69,69,0.5);
          box-shadow: 0 0 0 2px rgba(255,69,69,0.1);
        }

        .cred-input:disabled { opacity: 0.5; }

        .submit-creds-btn {
          padding: 9px 20px;
          background: linear-gradient(135deg, rgba(255,69,69,0.2), rgba(200,30,30,0.2));
          border: 1px solid var(--red);
          border-radius: 8px;
          color: var(--red);
          font-family: var(--font-mono);
          font-size: 0.72rem;
          font-weight: 700;
          letter-spacing: 0.12em;
          cursor: pointer;
          transition: all 0.2s;
        }

        .submit-creds-btn:hover:not(:disabled) {
          background: linear-gradient(135deg, rgba(255,69,69,0.3), rgba(200,30,30,0.3));
        }

        .submit-creds-btn:disabled { opacity: 0.4; cursor: not-allowed; }

        .sso-warning {
          font-size: 0.65rem;
          color: var(--yellow);
          margin-top: 8px;
          padding: 6px 10px;
          background: rgba(255,184,0,0.07);
          border: 1px solid rgba(255,184,0,0.2);
          border-radius: 6px;
        }

        /* ─── MESSAGES ─── */
        .messages-area {
          flex: 1;
          overflow-y: auto;
          padding: 20px 24px;
          display: flex;
          flex-direction: column;
          gap: 16px;
          scrollbar-width: thin;
          scrollbar-color: var(--border2) transparent;
        }

        .messages-area::-webkit-scrollbar { width: 4px; }
        .messages-area::-webkit-scrollbar-track { background: transparent; }
        .messages-area::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }

        .empty-state {
          margin: auto;
          text-align: center;
          max-width: 380px;
        }

        .empty-icon {
          font-size: 3rem;
          margin-bottom: 16px;
          display: block;
        }

        .empty-title {
          font-family: var(--font-display);
          font-size: 1.4rem;
          font-weight: 800;
          color: #fff;
          margin-bottom: 10px;
          letter-spacing: -0.02em;
        }

        .empty-desc {
          font-size: 0.78rem;
          color: var(--text-muted);
          line-height: 1.7;
        }

        .step-list {
          list-style: none;
          margin-top: 16px;
          display: flex;
          flex-direction: column;
          gap: 8px;
          text-align: left;
        }

        .step-item {
          display: flex;
          align-items: flex-start;
          gap: 10px;
          font-size: 0.72rem;
          color: var(--text-muted);
        }

        .step-num {
          width: 20px;
          height: 20px;
          background: rgba(0,229,255,0.1);
          border: 1px solid rgba(0,229,255,0.2);
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 0.6rem;
          font-weight: 700;
          color: var(--accent);
          flex-shrink: 0;
        }

        /* ─── MESSAGE BUBBLES ─── */
        .msg { display: flex; flex-direction: column; gap: 4px; animation: msg-in 0.25s ease; }

        @keyframes msg-in {
          from { opacity: 0; transform: translateY(8px); }
          to { opacity: 1; transform: translateY(0); }
        }

        .msg-user { align-items: flex-end; }
        .msg-assistant { align-items: flex-start; }
        .msg-system { align-items: center; }

        .msg-meta {
          font-size: 0.58rem;
          letter-spacing: 0.1em;
          color: var(--text-dim);
          text-transform: uppercase;
          display: flex;
          align-items: center;
          gap: 6px;
        }

        .msg-dot {
          width: 5px;
          height: 5px;
          border-radius: 50%;
        }

        .msg-user .msg-dot { background: var(--accent2); }
        .msg-assistant .msg-dot { background: var(--accent); }
        .msg-system .msg-dot { background: var(--text-dim); }

        .bubble {
          max-width: min(720px, 90%);
          padding: 12px 16px;
          border-radius: 12px;
          font-size: 0.82rem;
          line-height: 1.65;
          word-break: break-word;
        }

        .msg-user .bubble {
          background: var(--user-bg);
          border: 1px solid var(--user-border);
          border-bottom-right-radius: 4px;
          color: #d4c8f8;
        }

        .msg-assistant .bubble {
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-bottom-left-radius: 4px;
          color: var(--text);
        }

        .msg-system .bubble {
          background: var(--system-bg);
          border: 1px solid var(--system-border);
          border-radius: 8px;
          color: var(--text-muted);
          font-size: 0.72rem;
          padding: 8px 14px;
          max-width: 100%;
          text-align: center;
        }

        .bubble p { margin-bottom: 8px; }
        .bubble p:last-child { margin-bottom: 0; }
        .bubble h1, .bubble h2, .bubble h3 { margin-bottom: 8px; font-size: 0.95rem; color: #e2e8f0; }
        .bubble ul, .bubble ol { margin: 6px 0 8px 18px; }
        .bubble li { margin: 3px 0; }
        .bubble strong { color: var(--accent); font-weight: 700; }
        .bubble code { background: rgba(0,229,255,0.08); color: var(--accent); border-radius: 4px; padding: 1px 5px; font-size: 0.88em; }
        .bubble pre { background: #070910; border: 1px solid var(--border); border-radius: 8px; padding: 12px; overflow-x: auto; margin: 8px 0; }
        .bubble pre code { background: transparent; color: #a8d8f0; padding: 0; }
        .bubble a { color: var(--accent); text-decoration: underline; }

        .thinking {
          display: flex;
          align-items: center;
          gap: 10px;
          font-size: 0.72rem;
          color: var(--text-muted);
          padding: 10px 0;
        }

        .thinking-dots {
          display: flex;
          gap: 4px;
        }

        .thinking-dot {
          width: 5px;
          height: 5px;
          border-radius: 50%;
          background: var(--accent);
          animation: dot-pulse 1.2s ease infinite;
        }

        .thinking-dot:nth-child(2) { animation-delay: 0.2s; }
        .thinking-dot:nth-child(3) { animation-delay: 0.4s; }

        @keyframes dot-pulse {
          0%, 80%, 100% { opacity: 0.2; transform: scale(0.8); }
          40% { opacity: 1; transform: scale(1); }
        }

        /* ─── COMPOSER ─── */
        .composer {
          padding: 14px 24px 18px;
          border-top: 1px solid var(--border);
          background: var(--panel);
          flex-shrink: 0;
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .composer-inner {
          display: flex;
          gap: 10px;
          align-items: flex-end;
        }

        .composer-textarea {
          flex: 1;
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-radius: 10px;
          color: var(--text);
          font-family: var(--font-mono);
          font-size: 0.82rem;
          padding: 11px 14px;
          resize: none;
          line-height: 1.5;
          transition: border-color 0.2s;
        }

        .composer-textarea:focus {
          outline: none;
          border-color: var(--accent);
          box-shadow: 0 0 0 2px rgba(0,229,255,0.08);
        }

        .composer-textarea:disabled { opacity: 0.5; }

        .send-btn {
          padding: 11px 20px;
          background: linear-gradient(135deg, rgba(0,229,255,0.2), rgba(124,58,237,0.2));
          border: 1px solid var(--accent);
          border-radius: 10px;
          color: var(--accent);
          font-family: var(--font-mono);
          font-size: 0.75rem;
          font-weight: 700;
          letter-spacing: 0.1em;
          cursor: pointer;
          transition: all 0.2s;
          white-space: nowrap;
          flex-shrink: 0;
        }

        .send-btn:hover:not(:disabled) {
          background: linear-gradient(135deg, rgba(0,229,255,0.3), rgba(124,58,237,0.3));
          box-shadow: 0 0 12px rgba(0,229,255,0.2);
        }

        .send-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .composer-hint {
          font-size: 0.62rem;
          color: var(--text-dim);
          letter-spacing: 0.06em;
        }

        /* ─── ERROR BAR ─── */
        .error-bar {
          padding: 10px 24px;
          background: rgba(255,69,69,0.08);
          border-top: 1px solid rgba(255,69,69,0.2);
          font-size: 0.72rem;
          color: var(--red);
          flex-shrink: 0;
        }

        /* ─── CURSOR ─── */
        .cursor-blink {
          animation: blink 1s step-end infinite;
          color: var(--accent);
        }

        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }

