import { useEffect, useRef, useState, useCallback } from "react";
import axios from "axios";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8002";
const ANALYZE_URL_EP = `${API_BASE}/analyze-url`;
const ASK_URL_EP = `${API_BASE}/ask-question`;
const SUBMIT_CREDS_URL = `${API_BASE}/submit-credentials`;
const END_SESSION_URL = `${API_BASE}/session/end`;

axios.defaults.withCredentials = true;

const isProbablyUrl = (v) => /^https?:\/\/\S+$/i.test((v || "").trim());

const parseApiError = (err) => {
  const status = err?.response?.status;
  const detail = err?.response?.data?.detail;
  if (detail && typeof detail === "object") {
    return {
      status,
      message: detail.message || "Request failed.",
      authTypes: Array.isArray(detail.auth_types) ? detail.auth_types : [],
      requiredFields: Array.isArray(detail.required_fields) ? detail.required_fields : [],
    };
  }
  return {
    status,
    message: typeof detail === "string" ? detail : "Failed to get response from server.",
    authTypes: [],
    requiredFields: [],
  };
};

const isAnalyzeOnlyQuestion = (q) => {
  const t = (q || "").trim().toLowerCase();
  return ["analyze", "analyse", "analyze it", "analyse it", "analyze url", "check", "check it", "open", "open it"].includes(t);
};

const SESSION_DURATION = 3 * 60 * 60 * 1000; // 3 hours in ms

function TypewriterText({ text, speed = 18 }) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);
  useEffect(() => {
    setDisplayed("");
    setDone(false);
    if (!text) return;
    let i = 0;
    const iv = setInterval(() => {
      setDisplayed(text.slice(0, i + 1));
      i++;
      if (i >= text.length) {
        clearInterval(iv);
        setDone(true);
      }
    }, speed);
    return () => clearInterval(iv);
  }, [text, speed]);
  return <span>{displayed}{!done && <span className="cursor-blink">▌</span>}</span>;
}

function SessionTimer({ startTime }) {
  const [remaining, setRemaining] = useState(SESSION_DURATION);
  useEffect(() => {
    if (!startTime) return;
    const tick = () => {
      const elapsed = Date.now() - startTime;
      setRemaining(Math.max(0, SESSION_DURATION - elapsed));
    };
    tick();
    const iv = setInterval(tick, 1000);
    return () => clearInterval(iv);
  }, [startTime]);

  const h = Math.floor(remaining / 3600000);
  const m = Math.floor((remaining % 3600000) / 60000);
  const s = Math.floor((remaining % 60000) / 1000);
  const pct = (remaining / SESSION_DURATION) * 100;
  const color = pct > 50 ? "#00ff9d" : pct > 20 ? "#ffb800" : "#ff4545";

  return (
    <div className="session-timer">
      <div className="timer-label">SESSION EXPIRES</div>
      <div className="timer-value" style={{ color }}>
        {String(h).padStart(2, "0")}:{String(m).padStart(2, "0")}:{String(s).padStart(2, "0")}
      </div>
      <div className="timer-bar-track">
        <div className="timer-bar-fill" style={{ width: `${pct}%`, background: color }} />
      </div>
    </div>
  );
}

function CredentialField({ label, type = "text", value, onChange, disabled }) {
  return (
    <div className="cred-field">
      <label className="cred-label">{label}</label>
      <input
        className="cred-input"
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
        autoComplete="off"
      />
    </div>
  );
}

export default function App() {
  const [urlInput, setUrlInput] = useState("");
  const [question, setQuestion] = useState("");
  const [sessionId, setSessionId] = useState("");
  const [sessionStart, setSessionStart] = useState(null);
  const [activeUrl, setActiveUrl] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [phase, setPhase] = useState("idle"); // idle | analyzing | authing | chatting
  const [authRequired, setAuthRequired] = useState(false);
  const [authTypes, setAuthTypes] = useState([]);
  const [requiredFields, setRequiredFields] = useState([]);
  const [creds, setCreds] = useState({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
  const [error, setError] = useState("");
  const [urlLocked, setUrlLocked] = useState(false);
  const messagesEndRef = useRef(null);
  const questionRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  useEffect(() => {
    if (!sessionId) return;
    const handler = () => {
      navigator.sendBeacon(END_SESSION_URL, new Blob([JSON.stringify({ session_id: sessionId })], { type: "application/json" }));
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, [sessionId]);

  const addMsg = (role, content, meta = {}) => {
    setMessages((prev) => [...prev, { role, content, ts: Date.now(), ...meta }]);
  };

  const handleAnalyze = useCallback(async (urlToAnalyze) => {
    const url = urlToAnalyze || urlInput.trim();
    if (!url) return;
    setError("");
    setLoading(true);
    setPhase("analyzing");
    setUrlLocked(true);
    addMsg("system", `🔍 Scanning ${url}`);

    try {
      const resp = await axios.get(ANALYZE_URL_EP, { params: { url } });
      const { login_required, auth_types, required_fields, message, session_id, final_url } = resp.data;
      if (session_id && !sessionId) {
        setSessionId(session_id);
        setSessionStart(Date.now());
      }
      setActiveUrl(final_url || url);

      if (login_required) {
        setAuthRequired(true);
        setAuthTypes(auth_types || []);
        setRequiredFields(required_fields || []);
        setPhase("authing");
        addMsg("assistant", `🔐 **Authentication required** — this page is protected.\n\nDetected: \`${(auth_types || []).join(", ") || "login"}\`\n\nPlease enter your credentials below.`);
      } else {
        setPhase("chatting");
        addMsg("assistant", `✅ **Page loaded successfully!**\n\n${message}\n\nYou can now ask questions about the content.`);
      }
    } catch (err) {
      const e = parseApiError(err);
      setError(e.message);
      addMsg("system", `❌ ${e.message}`);
      setPhase("idle");
      setUrlLocked(false);
    } finally {
      setLoading(false);
    }
  }, [urlInput, sessionId]);

  const handleSubmitCredentials = async () => {
    if (!activeUrl || loading) return;
    setError("");
    setLoading(true);

    try {
      const payload = { url: activeUrl };
      if (creds.email.trim()) payload.email = creds.email.trim();
      if (creds.username.trim()) payload.username = creds.username.trim();
      if (creds.password) payload.password = creds.password;
      if (creds.otp.trim()) payload.otp = creds.otp.trim();
      if (creds.pin.trim()) payload.pin = creds.pin.trim();
      if (creds.verification_code.trim()) payload.verification_code = creds.verification_code.trim();

      const resp = await axios.post(SUBMIT_CREDS_URL, payload);
      const { authenticated, message, next_required, next_required_fields, session_id } = resp.data;
      if (session_id && !sessionId) {
        setSessionId(session_id);
        setSessionStart(Date.now());
      }

      if (authenticated) {
        setAuthRequired(false);
        setPhase("chatting");
        setCreds({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
        addMsg("assistant", `✅ **Authentication successful!**\n\n${message}\n\nStart asking questions about the page.`);
      } else {
        setAuthTypes(next_required || []);
        setRequiredFields(next_required_fields || []);
        addMsg("assistant", `⚠️ ${message}\n\nAdditional credentials may be required.`);
      }
    } catch (err) {
      const e = parseApiError(err);
      setError(e.message);
      addMsg("system", `❌ ${e.message}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSend = async () => {
    const q = question.trim();
    if (!q || loading || authRequired) return;

    if (!activeUrl && isProbablyUrl(urlInput.trim())) {
      addMsg("user", q);
      setQuestion("");
      await handleAnalyze(urlInput.trim());
      if (!isAnalyzeOnlyQuestion(q)) {
        // Will be picked up after auth/load
      }
      return;
    }

    if (!activeUrl) {
      setError("Please enter a URL first.");
      return;
    }

    addMsg("user", q);
    setQuestion("");
    setError("");
    setLoading(true);

    try {
      const resp = await axios.post(ASK_URL_EP, { question: q, url: activeUrl });
      const { answer, session_id } = resp.data;
      if (session_id && !sessionId) {
        setSessionId(session_id);
        setSessionStart(Date.now());
      }
      addMsg("assistant", answer);
    } catch (err) {
      const e = parseApiError(err);
      if (e.status === 401) {
        setAuthRequired(true);
        setAuthTypes(e.authTypes);
        setRequiredFields(e.requiredFields);
        setPhase("authing");
        addMsg("assistant", `🔐 **Session requires authentication.**\n\n${e.message}`);
      } else {
        setError(e.message);
        addMsg("system", `❌ ${e.message}`);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleNewChat = async () => {
    if (sessionId) {
      try {
        await axios.post(END_SESSION_URL, { session_id: sessionId });
      } catch {}
    }
    setSessionId("");
    setSessionStart(null);
    setActiveUrl("");
    setMessages([]);
    setQuestion("");
    setUrlInput("");
    setError("");
    setLoading(false);
    setPhase("idle");
    setAuthRequired(false);
    setAuthTypes([]);
    setRequiredFields([]);
    setCreds({ email: "", username: "", password: "", otp: "", pin: "", verification_code: "" });
    setUrlLocked(false);
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const showField = (name) =>
    requiredFields.length === 0 ? true : requiredFields.includes(name);

  const canSend = question.trim().length > 0 && !loading && !authRequired && (!!activeUrl || isProbablyUrl(urlInput.trim()));

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;700&family=Syne:wght@400;700;800&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        :root {
          --bg: #0a0c10;
          --panel: #0f1117;
          --panel2: #141720;
          --border: #1e2330;
          --border2: #252b3b;
          --text: #c8d3e8;
          --text-dim: #4a5568;
          --text-muted: #6b7a99;
          --accent: #00e5ff;
          --accent2: #7c3aed;
          --green: #00ff9d;
          --yellow: #ffb800;
          --red: #ff4545;
          --user-bg: #1a1040;
          --user-border: #3b1fa8;
          --system-bg: #0d1520;
          --system-border: #1e3050;
          --font-mono: 'JetBrains Mono', monospace;
          --font-display: 'Syne', sans-serif;
        }

        body {
          background: var(--bg);
          color: var(--text);
          font-family: var(--font-mono);
          min-height: 100vh;
          overflow-x: hidden;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          background:
            radial-gradient(ellipse 80% 40% at 20% 0%, rgba(0,229,255,0.04) 0%, transparent 60%),
            radial-gradient(ellipse 60% 30% at 80% 100%, rgba(124,58,237,0.06) 0%, transparent 60%);
          pointer-events: none;
          z-index: 0;
        }

        .app-shell {
          position: relative;
          z-index: 1;
          display: grid;
          grid-template-columns: 280px 1fr;
          height: 100vh;
          overflow: hidden;
        }

        /* ─── SIDEBAR ─── */
        .sidebar {
          background: var(--panel);
          border-right: 1px solid var(--border);
          display: flex;
          flex-direction: column;
          padding: 0;
          overflow: hidden;
        }

        .sidebar-logo {
          padding: 24px 20px 20px;
          border-bottom: 1px solid var(--border);
        }

        .logo-mark {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-bottom: 6px;
        }

        .logo-icon {
          width: 32px;
          height: 32px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          border-radius: 8px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 16px;
          flex-shrink: 0;
        }

        .logo-text {
          font-family: var(--font-display);
          font-weight: 800;
          font-size: 1.1rem;
          color: #fff;
          letter-spacing: -0.02em;
        }

        .logo-sub {
          font-size: 0.65rem;
          color: var(--text-muted);
          letter-spacing: 0.15em;
          text-transform: uppercase;
        }

        .sidebar-section {
          padding: 16px 20px;
          border-bottom: 1px solid var(--border);
        }

        .sidebar-section-title {
          font-size: 0.62rem;
          font-weight: 700;
          letter-spacing: 0.18em;
          text-transform: uppercase;
          color: var(--text-muted);
          margin-bottom: 10px;
        }

        .url-input-wrap {
          position: relative;
        }

        .url-input {
          width: 100%;
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-radius: 8px;
          color: var(--text);
          font-family: var(--font-mono);
          font-size: 0.72rem;
          padding: 9px 10px;
          transition: border-color 0.2s;
          resize: none;
          line-height: 1.5;
        }

        .url-input:focus {
          outline: none;
          border-color: var(--accent);
          box-shadow: 0 0 0 2px rgba(0,229,255,0.1);
        }

        .url-input:disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }

        .analyze-btn {
          width: 100%;
          margin-top: 8px;
          padding: 9px 12px;
          background: linear-gradient(135deg, rgba(0,229,255,0.15), rgba(124,58,237,0.15));
          border: 1px solid var(--accent);
          border-radius: 8px;
          color: var(--accent);
          font-family: var(--font-mono);
          font-size: 0.72rem;
          font-weight: 700;
          letter-spacing: 0.1em;
          cursor: pointer;
          transition: all 0.2s;
        }

        .analyze-btn:hover:not(:disabled) {
          background: linear-gradient(135deg, rgba(0,229,255,0.25), rgba(124,58,237,0.25));
        }

        .analyze-btn:disabled { opacity: 0.4; cursor: not-allowed; }

        .status-block {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .status-row {
          display: flex;
          align-items: center;
          justify-content: space-between;
          font-size: 0.68rem;
        }

        .status-key { color: var(--text-muted); }

        .status-val {
          font-weight: 700;
          font-size: 0.65rem;
          letter-spacing: 0.05em;
          padding: 2px 7px;
          border-radius: 4px;
        }

        .status-val.idle { background: #1a2030; color: var(--text-muted); }
        .status-val.analyzing { background: rgba(255,184,0,0.15); color: var(--yellow); }
        .status-val.authing { background: rgba(255,69,69,0.15); color: var(--red); }
        .status-val.chatting { background: rgba(0,255,157,0.12); color: var(--green); }

        .active-url-display {
          font-size: 0.63rem;
          color: var(--accent);
          word-break: break-all;
          line-height: 1.4;
          margin-top: 4px;
          padding: 6px 8px;
          background: rgba(0,229,255,0.05);
          border: 1px solid rgba(0,229,255,0.1);
          border-radius: 6px;
        }

        .sidebar-bottom {
          margin-top: auto;
          padding: 16px 20px;
          border-top: 1px solid var(--border);
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .new-chat-btn {
          width: 100%;
          padding: 9px;
          background: transparent;
          border: 1px solid var(--border2);
          border-radius: 8px;
          color: var(--text-muted);
          font-family: var(--font-mono);
          font-size: 0.7rem;
          font-weight: 600;
          letter-spacing: 0.1em;
          cursor: pointer;
          transition: all 0.2s;
        }

        .new-chat-btn:hover:not(:disabled) {
          border-color: var(--red);
          color: var(--red);
          background: rgba(255,69,69,0.05);
        }

        .new-chat-btn:disabled { opacity: 0.4; cursor: not-allowed; }

        .session-timer {
          text-align: center;
        }

        .timer-label {
          font-size: 0.58rem;
          letter-spacing: 0.15em;
          color: var(--text-muted);
          margin-bottom: 4px;
        }

        .timer-value {
          font-family: var(--font-mono);
          font-size: 1.1rem;
          font-weight: 700;
          letter-spacing: 0.08em;
          margin-bottom: 6px;
        }

        .timer-bar-track {
          height: 2px;
          background: var(--border2);
          border-radius: 1px;
          overflow: hidden;
        }

        .timer-bar-fill {
          height: 100%;
          border-radius: 1px;
          transition: width 1s linear, background 1s ease;
        }

        /* ─── MAIN AREA ─── */
        .main {
          display: flex;
          flex-direction: column;
          overflow: hidden;
          background: var(--bg);
        }

        .topbar {
          padding: 14px 24px;
          border-bottom: 1px solid var(--border);
          display: flex;
          align-items: center;
          justify-content: space-between;
          background: var(--panel);
          flex-shrink: 0;
        }

        .topbar-title {
          font-family: var(--font-display);
          font-size: 0.85rem;
          font-weight: 700;
          color: var(--text-dim);
          letter-spacing: 0.05em;
        }

        .topbar-right {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .session-badge {
          font-size: 0.62rem;
          letter-spacing: 0.12em;
          padding: 4px 10px;
          border-radius: 4px;
          font-weight: 700;
        }

        .session-badge.active {
          background: rgba(0,255,157,0.1);
          border: 1px solid rgba(0,255,157,0.3);
          color: var(--green);
        }

        .session-badge.inactive {
          background: rgba(255,69,69,0.08);
          border: 1px solid rgba(255,69,69,0.2);
          color: var(--red);
        }

        /* ─── AUTH PANEL ─── */
        .auth-panel {
          padding: 18px 24px;
          background: rgba(255,69,69,0.04);
          border-bottom: 1px solid rgba(255,69,69,0.15);
          flex-shrink: 0;
        }

        .auth-panel-header {
          display: flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 14px;
        }

        .auth-icon {
          width: 24px;
          height: 24px;
          background: rgba(255,69,69,0.15);
          border: 1px solid rgba(255,69,69,0.3);
          border-radius: 6px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 12px;
        }

        .auth-title {
          font-family: var(--font-display);
          font-size: 0.8rem;
          font-weight: 700;
          color: var(--red);
          letter-spacing: 0.08em;
        }

        .auth-subtitle {
          font-size: 0.65rem;
          color: var(--text-muted);
          margin-left: auto;
        }

        .cred-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
          gap: 10px;
          margin-bottom: 12px;
        }

        .cred-field { display: flex; flex-direction: column; gap: 4px; }

        .cred-label {
          font-size: 0.6rem;
          letter-spacing: 0.14em;
          text-transform: uppercase;
          color: var(--text-muted);
          font-weight: 700;
        }

        .cred-input {
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-radius: 6px;
          color: var(--text);
          font-family: var(--font-mono);
          font-size: 0.75rem;
          padding: 8px 10px;
          transition: border-color 0.2s;
        }

        .cred-input:focus {
          outline: none;
          border-color: rgba(255,69,69,0.5);
          box-shadow: 0 0 0 2px rgba(255,69,69,0.1);
        }

        .cred-input:disabled { opacity: 0.5; }

        .submit-creds-btn {
          padding: 9px 20px;
          background: linear-gradient(135deg, rgba(255,69,69,0.2), rgba(200,30,30,0.2));
          border: 1px solid var(--red);
          border-radius: 8px;
          color: var(--red);
          font-family: var(--font-mono);
          font-size: 0.72rem;
          font-weight: 700;
          letter-spacing: 0.12em;
          cursor: pointer;
          transition: all 0.2s;
        }

        .submit-creds-btn:hover:not(:disabled) {
          background: linear-gradient(135deg, rgba(255,69,69,0.3), rgba(200,30,30,0.3));
        }

        .submit-creds-btn:disabled { opacity: 0.4; cursor: not-allowed; }

        .sso-warning {
          font-size: 0.65rem;
          color: var(--yellow);
          margin-top: 8px;
          padding: 6px 10px;
          background: rgba(255,184,0,0.07);
          border: 1px solid rgba(255,184,0,0.2);
          border-radius: 6px;
        }

        /* ─── MESSAGES ─── */
        .messages-area {
          flex: 1;
          overflow-y: auto;
          padding: 20px 24px;
          display: flex;
          flex-direction: column;
          gap: 16px;
          scrollbar-width: thin;
          scrollbar-color: var(--border2) transparent;
        }

        .messages-area::-webkit-scrollbar { width: 4px; }
        .messages-area::-webkit-scrollbar-track { background: transparent; }
        .messages-area::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }

        .empty-state {
          margin: auto;
          text-align: center;
          max-width: 380px;
        }

        .empty-icon {
          font-size: 3rem;
          margin-bottom: 16px;
          display: block;
        }

        .empty-title {
          font-family: var(--font-display);
          font-size: 1.4rem;
          font-weight: 800;
          color: #fff;
          margin-bottom: 10px;
          letter-spacing: -0.02em;
        }

        .empty-desc {
          font-size: 0.78rem;
          color: var(--text-muted);
          line-height: 1.7;
        }

        .step-list {
          list-style: none;
          margin-top: 16px;
          display: flex;
          flex-direction: column;
          gap: 8px;
          text-align: left;
        }

        .step-item {
          display: flex;
          align-items: flex-start;
          gap: 10px;
          font-size: 0.72rem;
          color: var(--text-muted);
        }

        .step-num {
          width: 20px;
          height: 20px;
          background: rgba(0,229,255,0.1);
          border: 1px solid rgba(0,229,255,0.2);
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 0.6rem;
          font-weight: 700;
          color: var(--accent);
          flex-shrink: 0;
        }

        /* ─── MESSAGE BUBBLES ─── */
        .msg { display: flex; flex-direction: column; gap: 4px; animation: msg-in 0.25s ease; }

        @keyframes msg-in {
          from { opacity: 0; transform: translateY(8px); }
          to { opacity: 1; transform: translateY(0); }
        }

        .msg-user { align-items: flex-end; }
        .msg-assistant { align-items: flex-start; }
        .msg-system { align-items: center; }

        .msg-meta {
          font-size: 0.58rem;
          letter-spacing: 0.1em;
          color: var(--text-dim);
          text-transform: uppercase;
          display: flex;
          align-items: center;
          gap: 6px;
        }

        .msg-dot {
          width: 5px;
          height: 5px;
          border-radius: 50%;
        }

        .msg-user .msg-dot { background: var(--accent2); }
        .msg-assistant .msg-dot { background: var(--accent); }
        .msg-system .msg-dot { background: var(--text-dim); }

        .bubble {
          max-width: min(720px, 90%);
          padding: 12px 16px;
          border-radius: 12px;
          font-size: 0.82rem;
          line-height: 1.65;
          word-break: break-word;
        }

        .msg-user .bubble {
          background: var(--user-bg);
          border: 1px solid var(--user-border);
          border-bottom-right-radius: 4px;
          color: #d4c8f8;
        }

        .msg-assistant .bubble {
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-bottom-left-radius: 4px;
          color: var(--text);
        }

        .msg-system .bubble {
          background: var(--system-bg);
          border: 1px solid var(--system-border);
          border-radius: 8px;
          color: var(--text-muted);
          font-size: 0.72rem;
          padding: 8px 14px;
          max-width: 100%;
          text-align: center;
        }

        .bubble p { margin-bottom: 8px; }
        .bubble p:last-child { margin-bottom: 0; }
        .bubble h1, .bubble h2, .bubble h3 { margin-bottom: 8px; font-size: 0.95rem; color: #e2e8f0; }
        .bubble ul, .bubble ol { margin: 6px 0 8px 18px; }
        .bubble li { margin: 3px 0; }
        .bubble strong { color: var(--accent); font-weight: 700; }
        .bubble code { background: rgba(0,229,255,0.08); color: var(--accent); border-radius: 4px; padding: 1px 5px; font-size: 0.88em; }
        .bubble pre { background: #070910; border: 1px solid var(--border); border-radius: 8px; padding: 12px; overflow-x: auto; margin: 8px 0; }
        .bubble pre code { background: transparent; color: #a8d8f0; padding: 0; }
        .bubble a { color: var(--accent); text-decoration: underline; }

        .thinking {
          display: flex;
          align-items: center;
          gap: 10px;
          font-size: 0.72rem;
          color: var(--text-muted);
          padding: 10px 0;
        }

        .thinking-dots {
          display: flex;
          gap: 4px;
        }

        .thinking-dot {
          width: 5px;
          height: 5px;
          border-radius: 50%;
          background: var(--accent);
          animation: dot-pulse 1.2s ease infinite;
        }

        .thinking-dot:nth-child(2) { animation-delay: 0.2s; }
        .thinking-dot:nth-child(3) { animation-delay: 0.4s; }

        @keyframes dot-pulse {
          0%, 80%, 100% { opacity: 0.2; transform: scale(0.8); }
          40% { opacity: 1; transform: scale(1); }
        }

        /* ─── COMPOSER ─── */
        .composer {
          padding: 14px 24px 18px;
          border-top: 1px solid var(--border);
          background: var(--panel);
          flex-shrink: 0;
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .composer-inner {
          display: flex;
          gap: 10px;
          align-items: flex-end;
        }

        .composer-textarea {
          flex: 1;
          background: var(--panel2);
          border: 1px solid var(--border2);
          border-radius: 10px;
          color: var(--text);
          font-family: var(--font-mono);
          font-size: 0.82rem;
          padding: 11px 14px;
          resize: none;
          line-height: 1.5;
          transition: border-color 0.2s;
        }

        .composer-textarea:focus {
          outline: none;
          border-color: var(--accent);
          box-shadow: 0 0 0 2px rgba(0,229,255,0.08);
        }

        .composer-textarea:disabled { opacity: 0.5; }

        .send-btn {
          padding: 11px 20px;
          background: linear-gradient(135deg, rgba(0,229,255,0.2), rgba(124,58,237,0.2));
          border: 1px solid var(--accent);
          border-radius: 10px;
          color: var(--accent);
          font-family: var(--font-mono);
          font-size: 0.75rem;
          font-weight: 700;
          letter-spacing: 0.1em;
          cursor: pointer;
          transition: all 0.2s;
          white-space: nowrap;
          flex-shrink: 0;
        }

        .send-btn:hover:not(:disabled) {
          background: linear-gradient(135deg, rgba(0,229,255,0.3), rgba(124,58,237,0.3));
          box-shadow: 0 0 12px rgba(0,229,255,0.2);
        }

        .send-btn:disabled { opacity: 0.35; cursor: not-allowed; }

        .composer-hint {
          font-size: 0.62rem;
          color: var(--text-dim);
          letter-spacing: 0.06em;
        }

        /* ─── ERROR BAR ─── */
        .error-bar {
          padding: 10px 24px;
          background: rgba(255,69,69,0.08);
          border-top: 1px solid rgba(255,69,69,0.2);
          font-size: 0.72rem;
          color: var(--red);
          flex-shrink: 0;
        }

        /* ─── CURSOR ─── */
        .cursor-blink {
          animation: blink 1s step-end infinite;
          color: var(--accent);
        }

        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }

        /* ─── RESPONSIVE ─── */
        @media (max-width: 768px) {
          .app-shell {
            grid-template-columns: 1fr;
            grid-template-rows: auto 1fr;
          }

          .sidebar {
            flex-direction: row;
            flex-wrap: wrap;
            height: auto;
            border-right: none;
            border-bottom: 1px solid var(--border);
          }

          .sidebar-logo { width: 100%; }
          .sidebar-section { flex: 1; min-width: 200px; }
          .sidebar-bottom { width: 100%; border-top: 1px solid var(--border); flex-direction: row; }
        }
      `}</style>

      <div className="app-shell">
        {/* ─── SIDEBAR ─── */}
        <aside className="sidebar">
          <div className="sidebar-logo">
            <div className="logo-mark">
              <div className="logo-icon">🌐</div>
              <div>
                <div className="logo-text">WebAgent AI</div>
              </div>
            </div>
            <div className="logo-sub">Powered by Ollama + Playwright</div>
          </div>

          <div className="sidebar-section">
            <div className="sidebar-section-title">Target URL</div>
            <div className="url-input-wrap">
              <textarea
                className="url-input"
                rows={3}
                placeholder="https://example.com"
                value={urlInput}
                onChange={(e) => setUrlInput(e.target.value)}
                disabled={loading || urlLocked}
              />
            </div>
            <button
              className="analyze-btn"
              onClick={() => handleAnalyze()}
              disabled={loading || !urlInput.trim() || urlLocked}
            >
              {loading && phase === "analyzing" ? "[ SCANNING... ]" : "[ ANALYZE URL ]"}
            </button>
          </div>

          <div className="sidebar-section">
            <div className="sidebar-section-title">Status</div>
            <div className="status-block">
              <div className="status-row">
                <span className="status-key">AGENT</span>
                <span className={`status-val ${phase}`}>
                  {phase === "idle" ? "STANDBY" :
                   phase === "analyzing" ? "SCANNING" :
                   phase === "authing" ? "AUTH REQ" : "ACTIVE"}
                </span>
              </div>
              <div className="status-row">
                <span className="status-key">SESSION</span>
                <span className={`status-val ${sessionId ? "chatting" : "idle"}`}>
                  {sessionId ? "LIVE" : "NONE"}
                </span>
              </div>
              {activeUrl && (
                <div className="active-url-display">{activeUrl}</div>
              )}
            </div>
          </div>

          <div className="sidebar-bottom">
            {sessionId && <SessionTimer startTime={sessionStart} />}
            <button className="new-chat-btn" onClick={handleNewChat} disabled={loading}>
              ↺ RESET SESSION
            </button>
          </div>
        </aside>

        {/* ─── MAIN ─── */}
        <main className="main">
          <div className="topbar">
            <div className="topbar-title">
              {activeUrl ? `// ${activeUrl.replace(/^https?:\/\//, "").slice(0, 50)}` : "// No active target"}
            </div>
            <div className="topbar-right">
              <span className={`session-badge ${sessionId ? "active" : "inactive"}`}>
                {sessionId ? `SID: ${sessionId.slice(0, 8)}...` : "NO SESSION"}
              </span>
            </div>
          </div>

          {/* AUTH PANEL */}
          {authRequired && (
            <div className="auth-panel">
              <div className="auth-panel-header">
                <div className="auth-icon">🔐</div>
                <div className="auth-title">AUTHENTICATION REQUIRED</div>
                <div className="auth-subtitle">
                  {(requiredFields.length > 0 ? requiredFields : authTypes).join(" · ")}
                </div>
              </div>
              <div className="cred-grid">
                {showField("email") && (
                  <CredentialField label="Email" type="email" value={creds.email}
                    onChange={(v) => setCreds((p) => ({ ...p, email: v }))} disabled={loading} />
                )}
                {showField("username") && (
                  <CredentialField label="Username" value={creds.username}
                    onChange={(v) => setCreds((p) => ({ ...p, username: v }))} disabled={loading} />
                )}
                {showField("password") && (
                  <CredentialField label="Password" type="password" value={creds.password}
                    onChange={(v) => setCreds((p) => ({ ...p, password: v }))} disabled={loading} />
                )}
                {showField("otp") && (
                  <CredentialField label="OTP Code" value={creds.otp}
                    onChange={(v) => setCreds((p) => ({ ...p, otp: v }))} disabled={loading} />
                )}
                {showField("pin") && (
                  <CredentialField label="PIN" value={creds.pin}
                    onChange={(v) => setCreds((p) => ({ ...p, pin: v }))} disabled={loading} />
                )}
                {showField("verification_code") && (
                  <CredentialField label="Verification Code" value={creds.verification_code}
                    onChange={(v) => setCreds((p) => ({ ...p, verification_code: v }))} disabled={loading} />
                )}
              </div>
              <button className="submit-creds-btn" onClick={handleSubmitCredentials} disabled={loading}>
                {loading ? "[ AUTHENTICATING... ]" : "[ SUBMIT CREDENTIALS ]"}
              </button>
              {(authTypes.includes("sso") || authTypes.includes("captcha")) && (
                <div className="sso-warning">
                  ⚠ SSO / CAPTCHA detected — automated login may be blocked. Consider using a simpler page.
                </div>
              )}
            </div>
          )}

          {/* MESSAGES */}
          <div className="messages-area">
            {messages.length === 0 ? (
              <div className="empty-state">
                <span className="empty-icon">⬡</span>
                <div className="empty-title">AI Web Agent</div>
                <div className="empty-desc">
                  Paste a URL, analyze it, and interrogate its contents using natural language. Supports login-protected pages.
                </div>
                <ol className="step-list">
                  {[
                    "Enter a URL in the sidebar",
                    "Click Analyze URL to scan the page",
                    "Provide credentials if login is required",
                    "Ask questions about the page content",
                  ].map((s, i) => (
                    <li key={i} className="step-item">
                      <span className="step-num">{i + 1}</span>
                      <span>{s}</span>
                    </li>
                  ))}
                </ol>
              </div>
            ) : (
              messages.map((msg, i) => (
                <div key={i} className={`msg msg-${msg.role}`}>
                  <div className="msg-meta">
                    <span className="msg-dot" />
                    {msg.role === "user" ? "YOU" : msg.role === "system" ? "AGENT" : "AI"}
                    <span style={{ marginLeft: 4, opacity: 0.5 }}>
                      {new Date(msg.ts).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" })}
                    </span>
                  </div>
                  <div className="bubble">
                    {msg.role === "assistant" ? (
                      <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.content}</ReactMarkdown>
                    ) : (
                      msg.content
                    )}
                  </div>
                </div>
              ))
            )}

            {loading && (
              <div className="thinking">
                <div className="thinking-dots">
                  <div className="thinking-dot" />
                  <div className="thinking-dot" />
                  <div className="thinking-dot" />
                </div>
                {phase === "analyzing" ? "Scanning page..." : phase === "authing" ? "Authenticating..." : "Generating response..."}
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* COMPOSER */}
          <div className="composer">
            <div className="composer-inner">
              <textarea
                ref={questionRef}
                className="composer-textarea"
                placeholder={
                  authRequired
                    ? "Submit credentials above to continue..."
                    : phase === "idle"
                    ? "Enter a URL in the sidebar, then ask a question..."
                    : "Ask a question about the page..."
                }
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
                onKeyDown={handleKeyDown}
                rows={3}
                disabled={loading || authRequired}
              />
              <button className="send-btn" onClick={handleSend} disabled={!canSend}>
                {loading ? "..." : "SEND ↵"}
              </button>
            </div>
            <div className="composer-hint">↵ Enter to send · Shift+↵ newline · Session auto-expires in 3h</div>
          </div>

          {error && <div className="error-bar">⚠ {error}</div>}
        </main>
      </div>
    </>
  );
}
